<template>
<section class="custtableopt">
    <loader :is-visible="isLoading"></loader>

    <tg-list :IsShowAction="true" ModuleName="BillingRule" SubModuleCode="BillingRule" :LegendArray="[]" :RenderRowActionMethod="renderActions" v-on:ActionButtonClick="actionButtonClick" :widgets="[]" IdentityColumn="UTILITY_ID" :listType="['List']" 
    :ListData="UtilityData" :HeaderData="Headers" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" IsSearchFieldsOnTop="false" SearchPosition="" :ListDataCallBackFunction="FetchData" :showCheckBox="false" :SortExp="SortExp" :SortBy="SortBy" :NorecordfoundText="$t('NoRecordfound')" :isShowHeaderText="false" v-on:LeftsearchButtonClick="leftCommonSearch" v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:SortdataButtonClick="sortdata" :routeInfo="$router">
        <template v-slot:slotdata="{ data }">
            <template v-if="data.column.COLUMN_NAME == 'SERIAL_NUMBER'">
                <span>
                    <div class="text-center">
                        <span   :title="data.row.SERIAL_NUMBER" class="">{{data.row.SERIAL_NUMBER}}.</span>
                    </div>
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'UTILITY_NAME'">
                <span>
                    <div class="text">
                        <span   :title="data.row.UTILITY_NAME" class="">{{data.row.UTILITY_NAME}}</span>
                    </div>
                </span>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'EFFECTIVE_FROM'">
                <div class="input-group mb-3">
                    <v-date-picker mode=" date" class="timedate input-group" v-model="data.row.EFFECTIVE_FROM" :max-date="new Date()" :popover="{ visibility: 'click' }">
                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                        <input placeholder="MM/DD/YYYY" @click="togglePopover()" class="form-control" :value="inputValue" v-on="inputEvents" />
                        <div @click="togglePopover()" class="input-group-append">
                            <span class="input-group-text"><em class="fa fa-calendar"></em></span>
                        </div>
                    </template>
                    </v-date-picker>
                </div>
            </template>
            <template v-if="data.column.COLUMN_NAME == 'EFFECTIVE_TO'">

                <div class="input-group mb-3">
                        <v-date-picker mode=" date" class="timedate input-group" v-model="data.row.EFFECTIVE_TO" :popover="{ visibility: 'click' }">
                    <template v-slot="{ inputValue, inputEvents, togglePopover }">
                        <input placeholder="MM/DD/YYYY" @click="togglePopover()" class="form-control" :value="inputValue" v-on="inputEvents" />
                        <div @click="togglePopover()" class="input-group-append">
                            <span class="input-group-text"><em class="fa fa-calendar"></em></span>
                        </div>
                    </template>
                    </v-date-picker>
                </div>

            </template>
        </template>
    </tg-list>
    <!-- :HeaderButtons="listheaderbuttons"  -->

</section>
</template>

<script>
import DataService from '../../services/DataService';
import {
    MonthPickerInput
} from 'vue-month-picker'
export default {
    components: {
        MonthPickerInput
    },
    props: {
        ClientId: {
            type: Number,
            require: false
        }
    },

    components: {},

    data() {
        return {
            isLoading: false,
            FormSchema: [{
                    layoutType: "four",
                    Data: [{
                            astype: "SelectField",
                            label: this.$t('Contract/Customer Name'),
                            name: "CustomerName",
                            value: "",
                            visibility: true,
                            placeholder: "CustomerName",
                            disabled: false,
                            config: {
                                options: [],
                            },
                            validationRules: {
                                "required": true
                            },
                        },

                    ]
                },

            ],
            listActions: [{
                title: 'Refresh',
                href: 'javascript:void(0)',
                icon: 'fa fa-repeat text-primary fa-size',
                callbackfunction: 'Refresh',
                additionalSpan: ''
            }],
            UtilityData: [],
            isCloneModel: false,
            listheaderbuttons: [],
            cloneItem: [],
            StatusListForListing: [{
                    STATUS: "Active",
                    STATUS_ID: 1001,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#28a745",
                },
                {
                    STATUS: "Inactive",
                    STATUS_ID: 1002,
                    STATUS_COLOR: "#ffffff",
                    STATUS_BG_COLOR: "#d72435",
                },
            ],
            Headers: [{
                    "COLUMN_NAME": "SERIAL_NUMBER",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('SerialNumber'),
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('UtilityName'),
                    "DISPLAY_ORDER": 2,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "EFFECTIVE_FROM",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveFrom') + '*',
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "EFFECTIVE_TO",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('EffectiveTo') + '*',
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true
                    }
                },
                // {
                //     "COLUMN_NAME": "Action",
                //     "DATA_TYPE": "text",
                //     "SORTABLE": true,
                //     "VISIBLE": false,
                //     "DISPLAY_NAME": 'Action',
                //     "DISPLAY_ORDER": 4,
                // },             

            ],
            leftSearchFields: [],
            searchByName: '',
            searchByClientName: '',
            utilities: '',
            searchByState: [],
            SortBy: '',
            SortExp: '',
            noRecords: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            searchCondition: '',
            ListingData: [],
            servicePlanId: '',
            isBillingHistoryPopup: false,
            EffectinveFrom: null,
            EffectinveTo: null,
            AllUtilityData: []
        }
    },

    watch: {
        ClientId() {
            debugger;
            this.FetchData();
        }
    },
    created: async function () {
        var vm = this;
        if (vm.ClientId) {
            vm.FetchData();
        }
    },
    methods: {

        SaveProcessReprocessCharge: async function (item) {
            var vm = this;
            vm.isLoading = true;
            if (!item.EFFECTIVE_FROM || !item.EFFECTIVE_TO) {
                 vm.isLoading = false;           
                 vm.ShowAlert(vm.$t("FillRequiredField"), "failure", true, vm.$t("Alert"));
                return;
            }
            const fromDate = new Date(item.EFFECTIVE_FROM);
            const toDate = new Date(item.EFFECTIVE_TO);
            if (fromDate > toDate) {
                 vm.isLoading = false;
                vm.ShowAlert(vm.$t("DateAssignTillMsg"), "failure", vm.$t('Alert'));
                return;
            }
            var param = `clientId=${vm.ClientId}&additionalId=${item.UTILITY_ID}&dateFrom=${this.$options.filters.formatDate(item.EFFECTIVE_FROM)}&dateTo=${this.$options.filters.formatDate(item.EFFECTIVE_TO)}`;

            try {
                const response = await DataService.SaveProcessReprocessCharge(param);
                if (response.data.result) {
                    const Result = response.data.result.data;
                    const check_item = response.data.result;
                    vm.isLoading = false;
                    debugger
                    if (Result.STATUS_CODE == 0) {
                        if (check_item.invoiceNumber == "NO") {
                            vm.ShowAlert(vm.$t('NoUtilityForDateRange'), "warning", true, vm.$t('Alert'));                           
                        }
                        else {                            
                            vm.ShowAlert(vm.$t('Total')+' '+ check_item.invoiceNumber + ' '+ vm.$t('SchedulerRuns'), "warning", true, vm.$t('Alert'));                           
                        }                        
                    } else if (Result.STATUS_CODE == 1) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('Process')]), "Success", true, vm.$t('Alert'));
                    } else if (Result.STATUS_CODE == 2) {
                        vm.$router.push({path: '/ClientBill/Index'});
                    } else if (Result.STATUS_CODE == 3) {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('invoiceNumberList')]), "failure", vm.$t('Alert'));
                       
                    } else if (Result.STATUS_CODE == 4) {
                        vm.$router.push({path: '/ClientBill/Index'});                        
                    } else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                         vm.isLoading = false;
                    }
                }else if(response.data.status=='Failure'){
                    vm.ShowAlert(response.data.msg, "failure", vm.$t('Alert'));
                     vm.isLoading = false;
                } 
                else {
                    vm.isLoading = false;
                }
            } catch (error) {
                console.error("Error fetching data:", error);
            }
        },
        FetchData: async function () {
            var vm = this;
            vm.UtilityData = [];
            vm.AllUtilityData = [];
            var url = `clientId=${this.ClientId}&configId=&reqFrom=reprocesscharge&clientIds=`;
            try {
                const response = await DataService.getUtilityList(url);
                if (response.data && response.data.length > 0) {

                    // keep full data
                    // vm.UtilityData = response.data;
                    vm.AllUtilityData = response.data;
                     debugger
                     vm.AllUtilityData.forEach((element) => {
                        element.EFFECTIVE_FROM = element.EFFECTIVE_FROM
                            ? new Date(element.EFFECTIVE_FROM)
                            : new Date();

                        element.EFFECTIVE_TO = element.EFFECTIVE_TO
                            ? new Date(element.EFFECTIVE_TO)
                            : new Date();
                    });

                    vm.TotalRecords = vm.AllUtilityData.length;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;
                    vm.noRecords = false;

                    // pagination slice
                    let startIndex = (vm.CurrentPage - 1) * vm.PageSize;
                    let endIndex = startIndex + vm.PageSize;

                    vm.UtilityData = vm.AllUtilityData.slice(startIndex, endIndex);
                } else {
                    vm.UtilityData = [];
                    vm.TotalRecords = 0;
                    vm.noRecords = true;
                }

            } catch (error) {
                console.error("Error fetching data:", error);
            }
        },

        renderActions(row) {
            let rtnActionArray = [];
            this.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Refresh':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },

        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (value.searchCondition) {
                let str = value.searchConditionJson;
                let result = str.split('=')[1];
                this.searchCondition = result;
            } else {
                this.searchCondition = "";
            }
            this.FetchData();
        },

        actionButtonClick: function (callbackfunction, item, index, event) {
            debugger
            switch (callbackfunction) {
                case 'Refresh':
                    this.SaveProcessReprocessCharge(item);
                    break;
            }
        },

        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddBillingRule":
                    this.AddBillingRule();
                    break;

            }
        },

        sortdata: function (sortBy) {

            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },

    }
}
</script>

<style>
.custtableopt .listing .table td:not(.overflow-visible):not(.mobile-action):not(.details-control) {
    overflow: visible !important;
}

.custtableopt .table-responsive.table-fix-header {
    overflow: visible !important;
    max-height: inherit !important;
}
</style>
